module decoder_2_to_4 (
    input wire [1:0] A,
    output reg [3:0] Y
);
    always @* begin
        case (A)
            2'b01: Y = 4'b0010;
            2'b10: Y = 4'b0100;
            2'b11: Y = 4'b1000;
            2'b00: Y = 4'b0001;
            default: Y = 4'b0000; // Default case (not strictly necessary)
        endcase
    end
endmodule
